+    internal procedure AllFulfillmentOrdersAssigned(SalesShipmentHeader: Record "Sales Shipment Header"; var AssignedFulfillmentOrderIds: Dictionary of [BigInteger, Code[20]]): Boolean
+    var
+        SalesShipmentLine: Record "Sales Shipment Line";
+        FulfillmentOrderLine: Record "Shpfy FulFillment Order Line";
+        OrderLine: Record "Shpfy Order Line";
+        HasAnyFulfillmentLines: Boolean;
+        HasNonAssignedFulfillmentLines: Boolean;
+    begin
+        SalesShipmentLine.Reset();
+        SalesShipmentLine.SetRange("Document No.", SalesShipmentHeader."No.");
+        SalesShipmentLine.SetRange(Type, SalesShipmentLine.Type::Item);
+        SalesShipmentLine.SetFilter("Shpfy Order Line Id", '<>%1', 0);
