+    local procedure NavigateToSalesCreditMemo(DocumentNo: Code[20]; ICDirectionType: Enum "IC Direction Type"; ICPartnerCode: Code[20]): Boolean
+    var
+        SalesHeader: Record "Sales Header";
+        SalesCreditMemo: Page "Sales Credit Memo";
+    begin
+        // An IC transaction line of type credit memo could navigate to either
+        // the sales credit memo, or the posted credit memo if it was posted after received
+
+        // We first attempt to find the Sales Credit Memo
+        case ICDirectionType of
+            ICDirectionType::Outgoing:
+                begin
+                    SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::"Credit Memo");
+                    SalesHeader.SetRange("No.", DocumentNo);
+                end;
+            ICDirectionType::Incoming:
+                begin
+                    SalesHeader.SetRange("External Document No.", DocumentNo);
+                    SalesHeader.SetRange("IC Direction", ICDirectionType);
+                    SalesHeader.SetRange("Sell-to IC Partner Code", ICPartnerCode);
+                    SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::"Credit Memo");
