+    local procedure UpdateServiceHeaderStatus()
+    var
+        ServHeader: Record "Service Header";
+        ServItemLine: Record "Service Item Line";
+        RepairStatus: Record "Repair Status";
+        RepairStatusPriority: Integer;
+        UseLineNo: Integer;
+    begin
+        GetServHeader();
+        
+        // Find the repair status with the highest priority (lowest priority number)
+        RepairStatusPriority := 999;
+        UseLineNo := 0;
+        
+        ServItemLine.Reset();
+        ServItemLine.SetRange("Document Type", "Document Type");
+        ServItemLine.SetRange("Document No.", "Document No.");
+        ServItemLine.SetFilter("Repair Status Code", '<>%1', '');
+        
+        if ServItemLine.Find('-') then
+            repeat
+                if RepairStatus.Get(ServItemLine."Repair Status Code") then begin
+                    if RepairStatus.Priority < RepairStatusPriority then begin
+                        RepairStatusPriority := RepairStatus.Priority;
+                        UseLineNo := ServItemLine."Line No.";
+                    end;
+                end;
+            until ServItemLine.Next() = 0;
+        
+        // Update the service header status based on the highest priority repair status
+        if UseLineNo <> 0 then begin
+            ServItemLine.Get("Document Type", "Document No.", UseLineNo);
+            if RepairStatus.Get(ServItemLine."Repair Status Code") then begin
+                ServHeader.Get(Rec."Document Type", Rec."Document No.");
+                if ServHeader.Status <> RepairStatus."Service Order Status" then begin
+                    ServHeader.SetValidatingFromLines(true);
+                    ServHeader.Validate(Status, RepairStatus."Service Order Status");
+                    ServHeader.Modify(false);
+                end;
+            end;
+        end;
+    end;
